func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIDOffset, ori := range oris {
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset
		type placement struct {
			idx       int
			deltaCost float64
			valid     bool
		}
		bestPlacement := placement{idx: -1, deltaCost: 1e18, valid: false}
		checkedSlots := make([]bool, MAXASSIGNS)
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestPlacement.deltaCost {
						bestPlacement.idx = i
						bestPlacement.deltaCost = delta
						bestPlacement.valid = true
					}
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
			checkedSlots[i] = true
		}
		if !bestPlacement.valid && dispatch.AssignsLen < MAXASSIGNS {
			for i := 0; i <= dispatch.AssignsLen; i++ {
				if i < dispatch.AssignsLen && checkedSlots[i] {
					continue
				}
				if i == dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				oldCost := dispatch.Assigns[i].Cost
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					newCost := dispatch.Assigns[i].Cost
					if newCost >= 0 {
						delta := newCost - oldCost
						if delta < bestPlacement.deltaCost {
							bestPlacement.idx = i
							bestPlacement.deltaCost = delta
							bestPlacement.valid = true
						}
					}
					if !bestPlacement.valid || i != bestPlacement.idx {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
					if i == dispatch.AssignsLen-1 && !bestPlacement.valid && i > dispatch.AssignsLen-1 {
						dispatch.AssignsLen--
					}
				} else if i == dispatch.AssignsLen-1 {
					dispatch.AssignsLen--
				}
				if bestPlacement.valid {
					break
				}
			}
		}
		if bestPlacement.valid {
			if bestPlacement.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestPlacement.idx + 1
			}
			dispatch.Assigns[bestPlacement.idx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestPlacement.idx].GenRoute()
		} else {
			inserted := false
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					dispatch.AssignsLen = i + 1
				}
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						inserted = true
						break
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
				if i >= dispatch.AssignsLen && !ok {
					dispatch.AssignsLen--
				}
			}
			if !inserted {
				lastIdx := dispatch.AssignsLen
				if lastIdx < MAXASSIGNS {
					dispatch.Assigns[lastIdx].AddShip(shipID, ori, des)
					dispatch.Assigns[lastIdx].GenRoute()
					dispatch.AssignsLen++
				}
